#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <string.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1

void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void init(int argc, char** argv)
{
    if (4 == argc) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
        pyramid_height = atoi(argv[3]);
    } else {
        printf("Usage: dynproc row_len col_len pyramid_height\n");
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; rows > n; n++)
        wall[n] = data + cols * n;
    result = new int[cols];

    int tmp_4 = M_SEED;
    srand(tmp_4);

    for (int i = 0; rows > i; i++) {
        for (int j = 0; cols > j; j++) {
            wall[i][j] = rand() % 10;
        }
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? (min) : ((x > (max)) ? (max) : (x))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

int calc_path(int *val_7, int *elem_37[2], int x_0, int var_1,
              int x_2, int tmp_32, int tmp_36)
{
    (void)x_2;
    (void)tmp_32;
    (void)tmp_36;

    if (x_0 <= 1) {
        return 0;
    }

    int cur = 0;
    int next = 1;

    for (int r = 0; r < x_0 - 1; r++) {
        int *prev = elem_37[cur];
        int *out = elem_37[next];
        int base = r * var_1;

        #pragma omp parallel for
        for (int c = 0; c < var_1; c++) {
            int left = prev[(c == 0) ? 0 : (c - 1)];
            int up = prev[c];
            int right = prev[(c == var_1 - 1) ? (var_1 - 1) : (c + 1)];
            int best = MIN(left, up);
            best = MIN(best, right);
            out[c] = best + val_7[base + c];
        }

        int tmp = cur;
        cur = next;
        next = tmp;
    }

    return cur;
}

int main(int argc, char** argv)
{
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int v_17 = (pyramid_height) * HALO;
    int v_13 = BLOCK_SIZE - (pyramid_height) * HALO * 2;
    int elem_9 = cols / v_13 + ((0 == cols % v_13) ? 0 : 1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",
           pyramid_height, cols, v_17, BLOCK_SIZE, elem_9, v_13);

    int *val_20;
    int *x_8[2];
    int size = rows * cols;

    x_8[0] = new int[cols];
    x_8[1] = new int[cols];
    for (int i = 0; i < cols; i++) {
        x_8[0][i] = data[i];
    }

    if (size > cols) {
        val_20 = new int[size - cols];
        memcpy(val_20, data + cols, sizeof(int) * (size - cols));
    } else {
        val_20 = new int[0];
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int var_29 = calc_path(val_20, x_8, rows, cols,
                           pyramid_height, elem_9, v_17);

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    for (int i = 0; i < cols; i++) {
        result[i] = x_8[var_29][i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    delete[] val_20;
    delete[] x_8[0];
    delete[] x_8[1];

    delete[] data;
    delete[] wall;
    delete[] result;

#ifdef TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
